import React, { useState, useEffect } from 'react';

function Dashboard() {
  const [trashData, setTrashData] = useState([]);
  const [adminData, setAdminData] = useState([]);
  const [activeAdmin, setActiveAdmin] = useState('');
  // State untuk menentukan halaman mana yang sedang dibuka (Dashboard atau Admin)
  const [activeMenu, setActiveMenu] = useState('dashboard');

  const fetchData = async () => {
    try {
      const resTrash = await fetch('http://127.0.0.1:5000/api/trash');
      const resultTrash = await resTrash.json();
      setTrashData(resultTrash);

      const resAdmins = await fetch('http://127.0.0.1:5000/api/admins');
      const resultAdmins = await resAdmins.json();
      setAdminData(resultAdmins);
    } catch (error) {
      console.error("Gagal ambil data:", error);
    }
  };

  useEffect(() => {
    const name = localStorage.getItem("nama_aktif");
    setActiveAdmin(name || "Admin");
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.appContainer}>
      <style>
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600;700&display=swap');
      </style>

      {/* --- SIDEBAR (KIRI) --- */}
      <aside style={styles.sidebar}>
        <div style={styles.logoArea}>
          <div style={styles.logoIcon}>P</div>
          <span style={styles.logoText}>SmartPoint</span>
        </div>

        <nav style={styles.navMenu}>
          <div 
            style={activeMenu === 'dashboard' ? styles.navItemActive : styles.navItem} 
            onClick={() => setActiveMenu('dashboard')}
          >
            <span style={styles.navIcon}>📊</span> Dashboard
          </div>

          <div 
            style={activeMenu === 'admin' ? styles.navItemActive : styles.navItem} 
            onClick={() => setActiveMenu('admin')}
          >
            <span style={styles.navIcon}>👤</span> User Admin
          </div>

          <div style={styles.navItem} onClick={() => { localStorage.clear(); window.location.href = "/"; }}>
            <span style={styles.navIcon}>🚪</span> Keluar
          </div>
        </nav>
      </aside>

      {/* --- MAIN CONTENT (KANAN) --- */}
      <main style={styles.mainContent}>
        <header style={styles.topHeader}>
          <div style={styles.breadcrumb}>Dashboard  {activeMenu === 'dashboard' ? '> Welcome' : '> User Admin'}</div>
          <div style={styles.userProfile}>
            <span style={styles.userName}>{activeAdmin}</span>
            <div style={styles.avatar}></div>
          </div>
        </header>

        <div style={styles.contentWrapper}>
          <h2 style={styles.welcomeText}>Selamat Datang</h2>

          {/* KONTEN BERGANTI TERGANTUNG MENU YANG DIKLIK */}
          {activeMenu === 'dashboard' ? (
            <>
              {/* STATS CARDS */}
              <div style={styles.statsGrid}>
                <div style={styles.statCard}>
                  <div style={styles.statIconBox}>📦</div>
                  <div>
                    <div style={styles.statValue}>{trashData.length}</div>
                    <div style={styles.statLabel}>Total Data Sampah</div>
                  </div>
                </div>
                <div style={styles.statCard}>
                  <div style={styles.statIconBox} style={{...styles.statIconBox, color:'#f39c12'}}>👥</div>
                  <div>
                    <div style={styles.statValue}>{adminData.length}</div>
                    <div style={styles.statLabel}>Total Admin</div>
                  </div>
                </div>
                <div style={styles.statCard}>
                  <div style={styles.statIconBox} style={{...styles.statIconBox, color:'#2ecc71'}}>🗑️</div>
                  <div>
                    <div style={styles.statValue}>113</div>
                    <div style={styles.statLabel}>Total Outlet/Bin</div>
                  </div>
                </div>
              </div>

              {/* REALTIME MONITORING TABLE */}
              <div style={styles.tableSection}>
                <h3 style={styles.tableTitle}>📊 Monitoring Real-time</h3>
                <div style={styles.tableCard}>
                  <table style={styles.table}>
                    <thead>
                      <tr>
                        <th style={styles.th}>ID BIN</th>
                        <th style={styles.th}>TIPE</th>
                        <th style={styles.th}>KAPASITAS</th>
                        <th style={styles.th}>STATUS</th>
                        <th style={styles.th}>WAKTU</th>
                      </tr>
                    </thead>
                    <tbody>
                      {trashData.map((item, index) => (
                        <tr key={index} style={styles.tr}>
                          <td style={styles.td}><strong>{item.bin_id}</strong></td>
                          <td style={styles.td}>{item.type}</td>
                          <td style={styles.td}>
                            <div style={styles.progressBar}>
                              <div style={{...styles.progressFill, width: `${item.percentage}%`, backgroundColor: item.percentage > 80 ? '#e74c3c' : '#2ecc71'}}></div>
                            </div>
                            <span style={{fontSize:'12px'}}>{Math.round(item.percentage)}%</span>
                          </td>
                          <td style={styles.td}>
                            <span style={item.status === 'penuh' ? styles.badgeRed : styles.badgeGreen}>{item.status}</span>
                          </td>
                          <td style={styles.td}>{new Date(item.created_at).toLocaleTimeString()}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </>
          ) : (
            /* TABEL ADMIN (Hanya muncul saat menu Admin diklik) */
            <div style={styles.tableSection}>
              <h3 style={styles.tableTitle}>👥 Daftar Admin Sistem</h3>
              <div style={styles.tableCard}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>NAMA ADMIN</th>
                      <th style={styles.th}>EMAIL</th>
                      <th style={styles.th}>STATUS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {adminData.map((admin, index) => (
                      <tr key={index} style={styles.tr}>
                        <td style={styles.td}><strong>{admin.name}</strong></td>
                        <td style={styles.td}>{admin.email}</td>
                        <td style={styles.td}><span style={styles.badgeGreen}>Active</span></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

const styles = {
  appContainer: { display: 'flex', minHeight: '100vh', backgroundColor: '#1a2c6d', fontFamily: "'Inter', sans-serif" },

  // SIDEBAR STYLES
  sidebar: { width: '260px', backgroundColor: '#1a2c6d', color: '#fff', padding: '30px 0' },
  logoArea: { display: 'flex', alignItems: 'center', padding: '0 30px', marginBottom: '50px' },
  logoIcon: { backgroundColor: '#fff', color: '#1a2c6d', width: '35px', height: '35px', borderRadius: '8px', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', marginRight: '12px' },
  logoText: { fontSize: '20px', fontWeight: 'bold', letterSpacing: '1px' },
  navMenu: { display: 'flex', flexDirection: 'column' },
  navItem: { padding: '15px 30px', cursor: 'pointer', color: '#a5b1d9', transition: '0.3s', display: 'flex', alignItems: 'center' },
  navItemActive: { padding: '15px 30px', cursor: 'pointer', backgroundColor: 'rgba(255,255,255,0.1)', borderLeft: '4px solid #fff', color: '#fff', display: 'flex', alignItems: 'center' },
  navIcon: { marginRight: '15px' },

  // MAIN CONTENT STYLES
  mainContent: { flex: 1, backgroundColor: '#f5f7fb', borderTopLeftRadius: '40px', padding: '30px' },
  topHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' },
  breadcrumb: { color: '#888', fontSize: '14px' },
  userProfile: { display: 'flex', alignItems: 'center' },
  userName: { marginRight: '15px', fontWeight: '600', color: '#333' },
  avatar: { width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#ddd' },

  contentWrapper: { padding: '0 10px' },
  welcomeText: { fontSize: '24px', fontWeight: 'bold', marginBottom: '30px', color: '#333' },

  // CARDS STYLES
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '25px', marginBottom: '40px' },
  statCard: { backgroundColor: '#fff', padding: '25px', borderRadius: '15px', display: 'flex', alignItems: 'center', boxShadow: '0 5px 20px rgba(0,0,0,0.03)' },
  statIconBox: { fontSize: '30px', marginRight: '20px', width: '60px', height: '60px', backgroundColor: '#f8f9fa', borderRadius: '12px', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  statValue: { fontSize: '24px', fontWeight: 'bold', color: '#333' },
  statLabel: { fontSize: '14px', color: '#888' },

  // TABLE STYLES
  tableSection: { marginTop: '20px' },
  tableTitle: { fontSize: '18px', fontWeight: 'bold', marginBottom: '20px', color: '#333' },
  tableCard: { backgroundColor: '#fff', borderRadius: '20px', padding: '20px', boxShadow: '0 5px 20px rgba(0,0,0,0.03)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', padding: '15px', color: '#888', fontSize: '13px', borderBottom: '1px solid #f0f0f0', fontWeight: '600' },
  td: { padding: '18px 15px', color: '#444', fontSize: '14px', borderBottom: '1px solid #f8f8f8' },
  tr: { transition: '0.2s' },

  // PROGRESS & BADGES
  progressBar: { width: '100px', height: '8px', backgroundColor: '#eee', borderRadius: '10px', marginBottom: '5px' },
  progressFill: { height: '100%', borderRadius: '10px', transition: 'width 0.5s' },
  badgeGreen: { backgroundColor: '#e8f5e9', color: '#2e7d32', padding: '6px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: '600' },
  badgeRed: { backgroundColor: '#ffebee', color: '#c62828', padding: '6px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: '600' },
};

export default Dashboard;
